/**
 * UserProfileModal - Quick profile preview popup
 *
 * Shows a compact profile preview when clicking on a user's avatar or name.
 * Provides quick access to view profile, follow, or view posts.
 */

import { useEffect, useRef, useCallback, useState } from 'react';
import { Link } from 'react-router-dom';
import { useUserProfile } from '../hooks/useUserProfile';
import { useMediaUpload } from '../hooks/useRpc';
import { getAvatarColor, getAvatarInitials, truncateAddress } from '../lib/profile';
import './UserProfileModal.css';

interface UserProfileModalProps {
  /** User's public key (hex) */
  userPk: string;
  /** Position to anchor the modal */
  anchorPosition: { x: number; y: number };
  /** Called when modal should close */
  onClose: () => void;
  /** Optional: display name if already known */
  displayName?: string;
}

export function UserProfileModal({
  userPk,
  anchorPosition,
  onClose,
  displayName: knownDisplayName,
}: UserProfileModalProps): JSX.Element {
  const modalRef = useRef<HTMLDivElement>(null);
  const { profile, loading } = useUserProfile(userPk);

  const displayName = profile?.info?.displayName || knownDisplayName || truncateAddress(userPk);
  const avatarColor = getAvatarColor(userPk);
  const initials = getAvatarInitials(profile?.info?.displayName, userPk);

  // Fetch the avatar image (the modal showed only initials before).
  const { getMediaUrl } = useMediaUpload();
  const [avatarUrl, setAvatarUrl] = useState<string | null>(null);
  const [showRepInfo, setShowRepInfo] = useState(false);
  const avatarContentId = profile?.avatar?.contentId;
  useEffect(() => {
    let alive = true;
    if (!avatarContentId) { setAvatarUrl(null); return; }
    const hash = avatarContentId.startsWith('sha256:')
      ? avatarContentId.slice('sha256:'.length)
      : avatarContentId;
    getMediaUrl(hash).then(url => { if (alive) setAvatarUrl(url); }).catch(() => { if (alive) setAvatarUrl(null); });
    return () => { alive = false; };
  }, [avatarContentId, getMediaUrl]);

  // Close on click outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (modalRef.current && !modalRef.current.contains(e.target as Node)) {
        onClose();
      }
    };

    // Close on escape
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onClose();
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleKeyDown);

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [onClose]);

  // Calculate position to keep modal in viewport
  const getPosition = useCallback(() => {
    const modalWidth = 280;
    const modalHeight = 200;
    const padding = 16;

    let x = anchorPosition.x;
    let y = anchorPosition.y + 8; // Offset below anchor

    // Check right boundary
    if (x + modalWidth > window.innerWidth - padding) {
      x = window.innerWidth - modalWidth - padding;
    }

    // Check left boundary
    if (x < padding) {
      x = padding;
    }

    // Check bottom boundary - show above if not enough space
    if (y + modalHeight > window.innerHeight - padding) {
      y = anchorPosition.y - modalHeight - 8;
    }

    return { left: x, top: y };
  }, [anchorPosition]);

  const position = getPosition();

  return (
    <div
      ref={modalRef}
      className="user-profile-modal"
      style={{ left: position.left, top: position.top }}
      role="dialog"
      aria-label={`Profile preview for ${displayName}`}
    >
      {loading ? (
        <div className="user-profile-modal__loading">
          <div className="user-profile-modal__loading-spinner" />
        </div>
      ) : (
        <>
          {/* Header with avatar and name */}
          <div className="user-profile-modal__header">
            <div
              className="user-profile-modal__avatar"
              style={avatarUrl ? undefined : { backgroundColor: avatarColor }}
            >
              {avatarUrl ? (
                <img src={avatarUrl} alt="" className="user-profile-modal__avatar-img" />
              ) : (
                initials
              )}
            </div>
            <div className="user-profile-modal__info">
              <div className="user-profile-modal__name">{displayName}</div>
              <div className="user-profile-modal__address">
                <code>{userPk.slice(0, 8)}...{userPk.slice(-6)}</code>
              </div>
            </div>
          </div>

          {/* Reputation trust signal (SPEC_12 §3.4) — informational only. Tap to
              explain (a hover `title` is invisible on touch devices). */}
          {profile?.reputation && (
            <>
              <button
                type="button"
                className="user-profile-modal__reputation"
                onClick={() => setShowRepInfo((v) => !v)}
                aria-expanded={showRepInfo}
                aria-label={`Trust signal: ${profile.reputation.effect}, score ${profile.reputation.score}. Tap for details.`}
              >
                <span className="user-profile-modal__reputation-badge">
                  {profile.reputation.badge}
                </span>
                <span className="user-profile-modal__reputation-label">
                  {profile.reputation.effect}
                </span>
                <span className="user-profile-modal__reputation-score">
                  {profile.reputation.score}
                </span>
                <span className="user-profile-modal__reputation-help" aria-hidden="true">
                  ⓘ
                </span>
              </button>
              {showRepInfo && (
                <p className="user-profile-modal__reputation-explainer">
                  <strong>{profile.reputation.effect}</strong> is a community
                  <em> trust signal</em> (score {profile.reputation.score}), not a
                  penalty by default. New accounts start here and rise with age and
                  positive community attestations; the score drops only if the
                  community flags posts as spam. It grants no posting privileges —
                  it just reflects standing.
                </p>
              )}
            </>
          )}

          {/* Bio if available */}
          {profile?.info?.bio && (
            <p className="user-profile-modal__bio">
              {profile.info.bio.length > 100
                ? profile.info.bio.slice(0, 100) + '...'
                : profile.info.bio}
            </p>
          )}

          {/* Actions */}
          <div className="user-profile-modal__actions">
            <Link
              to={`/profile/${userPk}`}
              className="user-profile-modal__action user-profile-modal__action--primary"
              onClick={onClose}
            >
              View Profile
            </Link>
            <Link
              to={`/?author=${userPk}`}
              className="user-profile-modal__action"
              onClick={onClose}
            >
              View Posts
            </Link>
          </div>
        </>
      )}
    </div>
  );
}

/**
 * Hook to manage UserProfileModal state
 */
export function useProfileModal() {
  const [modalState, setModalState] = useState<{
    isOpen: boolean;
    userPk: string | null;
    position: { x: number; y: number };
    displayName?: string;
  }>({
    isOpen: false,
    userPk: null,
    position: { x: 0, y: 0 },
  });

  const openModal = useCallback((
    userPk: string,
    event: React.MouseEvent,
    displayName?: string
  ) => {
    const rect = (event.currentTarget as HTMLElement).getBoundingClientRect();
    setModalState({
      isOpen: true,
      userPk,
      position: { x: rect.left, y: rect.bottom },
      displayName,
    });
  }, []);

  const closeModal = useCallback(() => {
    setModalState(prev => ({ ...prev, isOpen: false, userPk: null }));
  }, []);

  return {
    modalState,
    openModal,
    closeModal,
  };
}
